changeSet.sql:
CREATE INDEX IF NOT EXISTS idx_comm_template_updated_at
    ON communication.comm_template (updated_at DESC);

DROP INDEX IF EXISTS communication.idx_comm_delivery_status_next_attempt;
CREATE INDEX IF NOT EXISTS idx_comm_delivery_retry_queue
    ON communication.comm_delivery (status, next_attempt_at)
    WHERE status IN ('QUEUED', 'RETRYING');

changeSet.rollback:
DROP INDEX IF EXISTS communication.idx_comm_delivery_retry_queue;
CREATE INDEX IF NOT EXISTS idx_comm_delivery_status_next_attempt
    ON communication.comm_delivery (status, next_attempt_at);
DROP INDEX IF EXISTS communication.idx_comm_template_updated_at;
